t.script:

var PENDING_LOCKED = (function() {
    var banner = document.getElementById('pendingLockBanner');
    return !!banner;
})();

let isEditMode = false;
let originalFormData = {};
let activeProfileTab = 'basic';

/* ── Fix last updated timezone ── */
(function fixLastUpdatedTimezone() {
    var el = document.getElementById('profileLastUpdated');
    if (!el) return;
    var raw = el.textContent.trim();
    if (!raw || raw === 'Never') return;
    try {
        raw = raw.replace(/\u00a0/g, ' ').trim();
        var dt = new Date(raw);
        if (isNaN(dt.getTime())) {
            var m = raw.match(/(\d{1,2})\s+(\w+),?\s+(\d{4})\s+at\s+(\d{1,2}):(\d{2})\s*(AM|PM)/i);
            if (m) {
                var months = {jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
                var monIdx = months[m[2].toLowerCase().substring(0,3)];
                var hr = parseInt(m[4],10);
                var isPM = m[6].toUpperCase()==='PM';
                if (isPM && hr < 12) hr += 12;
                if (!isPM && hr === 12) hr = 0;
                dt = new Date(Date.UTC(parseInt(m[3],10), monIdx, parseInt(m[1],10), hr, parseInt(m[5],10)));
            }
        }
        if (!isNaN(dt.getTime())) {
            var opts = { day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit', hour12:true };
            el.textContent = dt.toLocaleString(undefined, opts);
        }
    } catch(e) {}
})();

function autosaveDraftNow() {
    if (!isEditMode) return;
    try {
        const draftData = {};
        document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(function(input) {
            if (input.type === 'hidden' || input.type === 'file') return;
            if (!input.name) return;
            draftData[input.name] = input.type === 'checkbox' ? (input.checked ? 'on' : '') : input.value;
        });
        localStorage.setItem('profileDraft', JSON.stringify(draftData));
    } catch(e) { console.error('autosave error', e); }
}

function switchProfileTab(tabKey) {
    const previousTab = activeProfileTab;
    activeProfileTab = tabKey;
    if (!isEditMode && previousTab && previousTab !== tabKey) {
        clearValidationStates(previousTab);
    }
    document.querySelectorAll('#personalDetailsForm .profile-tab-section').forEach(card => {
        card.style.display = card.getAttribute('data-tab-group') === tabKey ? '' : 'none';
    });
    document.querySelectorAll('#personalDetailsForm .profile-tab-button').forEach(btn => {
        const active = btn.getAttribute('data-tab-target') === tabKey;
        btn.classList.toggle('active', active);
        btn.setAttribute('aria-selected', active ? 'true' : 'false');
    });
}

function syncAndToggleEditMode(sourceCheckbox) {
    if (PENDING_LOCKED) {
        sourceCheckbox.checked = false;
        alert('Editing is disabled while your profile update is pending HR review.');
        return;
    }
    document.querySelectorAll('.edit-mode-toggle').forEach(t => { t.checked = sourceCheckbox.checked; });
    sourceCheckbox.checked ? enableEditMode() : disableEditMode();
}

function escapeHtml(str) {
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

/* ══════════════════════════════════════════════════════════════════════════
   CORE STATE FETCH HELPER — THE KEY FIX
   Temporarily removes disabled so browser renders selected option correctly,
   then re-adds disabled if we are NOT in edit mode.
   This fixes states showing blank on page load even when India is selected.
══════════════════════════════════════════════════════════════════════════ */
function _fetchStates(selectEl, countryId, selectedId) {
    if (!selectEl) return;
    if (!countryId || parseInt(countryId) <= 0) {
        selectEl.innerHTML = '<option value="">-- Select State --</option>';
        return;
    }
    var wasDisabled = selectEl.disabled;
    selectEl.disabled = false; /* MUST remove disabled before populating */
    selectEl.innerHTML = '<option value="">-- Loading... --</option>';

    fetch('/portal/get_states', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({
            jsonrpc: '2.0', id: Math.floor(Math.random()*99999),
            method: 'call',
            params: {country_id: parseInt(countryId)}
        })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
        var states = (data && data.result) ? data.result : [];
        selectEl.innerHTML = '<option value="">-- Select State --</option>';
        states.forEach(function(s) {
            var opt = document.createElement('option');
            opt.value = s.id;
            opt.textContent = s.name;
            if (selectedId && parseInt(selectedId) > 0 && s.id == parseInt(selectedId)) {
                opt.selected = true;
            }
            selectEl.appendChild(opt);
        });
        if (wasDisabled && !isEditMode) {
            selectEl.disabled = true;
        }
    })
    .catch(function(err) {
        console.error('State load error:', err);
        selectEl.innerHTML = '<option value="">-- Error loading states --</option>';
        if (wasDisabled && !isEditMode) selectEl.disabled = true;
    });
}

/* ══════════════════════════════════════════════════════════════════════════
   PUBLIC STATE LOADERS — all at global scope, never nested
══════════════════════════════════════════════════════════════════════════ */
function loadStatesByCountry(countryId) {
    _fetchStates(document.getElementById('statesDropdown'), countryId, 0);
}
function loadStatesByCountryAndSelect(countryId, selectedId) {
    _fetchStates(document.getElementById('statesDropdown'), countryId, selectedId);
}
function loadPermanentStatesByCountry(countryId) {
    _fetchStates(document.getElementById('permanentStateDropdown'), countryId, 0);
}
function loadPermanentStatesByCountryAndSelect(countryId, selectedId) {
    _fetchStates(document.getElementById('permanentStateDropdown'), countryId, selectedId);
}
function loadContactStates(countryId) {
    _fetchStates(document.getElementById('contactStateDropdown'), countryId, 0);
}
function loadContactStatesByCountryAndSelect(countryId, selectedId) {
    _fetchStates(document.getElementById('contactStateDropdown'), countryId, selectedId);
}

function enableEditMode() {
    if (PENDING_LOCKED) {
        alert('Editing is disabled while your profile update is pending HR review.');
        return;
    }
    isEditMode = true;
    document.querySelectorAll('.edit-mode-toggle').forEach(t => t.checked = true);
    storeOriginalFormData();

    var editBtn = document.getElementById('editProfileBtn');
    if (editBtn) {
        editBtn.classList.remove('btn-outline-primary');
        editBtn.classList.add('btn-primary', 'edit-active');
        editBtn.innerHTML = '<i class="fa fa-pencil me-1"></i>Editing Mode ON';
    }

    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        if (input.type === 'hidden') return;
        if (input.classList.contains('edit-mode-toggle')) return;
        if (input.hasAttribute('data-always-readonly')) {
            input.setAttribute('readonly', 'readonly');
            if (input.tagName === 'SELECT' || input.type === 'checkbox') input.setAttribute('disabled', 'disabled');
            input.style.setProperty('pointer-events', 'none');
            input.style.setProperty('background-color', '#e9ecef');
            return;
        }
        if (input.type === 'file') { input.removeAttribute('disabled'); return; }
        input.removeAttribute('readonly');
        input.removeAttribute('disabled');
        input.style.removeProperty('pointer-events');
        input.style.removeProperty('background-color');
    });

    document.getElementById('formActions').style.display = 'block';
    document.getElementById('viewActions').style.display = 'none';
    const disc = document.getElementById('personalDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('personalSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }

    document.querySelectorAll('#personalDetailsForm input[type="file"].file-upload-input').forEach(fileInput => {
        fileInput.addEventListener('change', function() {
            if (this.files && this.files.length > 0) { showFilePreview(this, this.files[0]); }
            else { this.value = ''; clearFilePreview(this); }
        });
    });

    document.querySelectorAll('#personalDetailsForm input:not([type="file"]), #personalDetailsForm select').forEach(input => {
        input.removeEventListener('input', validateField);
        input.removeEventListener('blur', validateField);
        input.removeEventListener('change', autosaveDraftNow);
        input.removeEventListener('input', autosaveDraftNow);
        input.addEventListener('input', validateField);
        input.addEventListener('blur', validateField);
        input.addEventListener('input', autosaveDraftNow);
        input.addEventListener('change', autosaveDraftNow);
    });

    /* Re-populate state dropdowns when entering edit mode */
    setTimeout(function() {
        var workCountrySel = document.querySelector('select[name="countries_id"]');
        if (workCountrySel && workCountrySel.value) {
            var workStateSel = document.getElementById('statesDropdown');
            var saved = workStateSel ? (workStateSel.value || workStateSel.getAttribute('data-saved-value') || '0') : '0';
            _fetchStates(workStateSel, workCountrySel.value, saved);
        }
        var permCountrySel = document.querySelector('select[name="private_country_id"]');
        if (permCountrySel && permCountrySel.value) {
            var permStateSel = document.getElementById('permanentStateDropdown');
            var saved2 = permStateSel ? (permStateSel.value || permStateSel.getAttribute('data-saved-value') || '0') : '0';
            _fetchStates(permStateSel, permCountrySel.value, saved2);
        }
        var contactCountrySel = document.querySelector('select[name="country_residences_id"]');
        if (contactCountrySel && contactCountrySel.value) {
            var contactStateSel = document.getElementById('contactStateDropdown');
            var saved3 = contactStateSel ? (contactStateSel.value || contactStateSel.getAttribute('data-saved-value') || '0') : '0';
            _fetchStates(contactStateSel, contactCountrySel.value, saved3);
        }
    }, 150);
}

function disableEditMode() {
    isEditMode = false;
    localStorage.removeItem('profileEditActive');
    localStorage.removeItem('profileDraft');
    document.querySelectorAll('.edit-mode-toggle').forEach(t => t.checked = false);

    var editBtn = document.getElementById('editProfileBtn');
    if (editBtn) {
        editBtn.classList.remove('btn-primary', 'edit-active');
        editBtn.classList.add('btn-outline-primary');
        editBtn.innerHTML = '<i class="fa fa-edit me-1"></i>Edit Profile';
    }

    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        if (input.type === 'hidden') return;
        if (input.classList.contains('edit-mode-toggle')) return;
        if (input.hasAttribute('data-always-readonly')) {
            input.setAttribute('readonly', 'readonly');
            if (input.tagName === 'SELECT' || input.type === 'checkbox') input.setAttribute('disabled', 'disabled');
            input.style.setProperty('pointer-events', 'none');
            input.style.setProperty('background-color', '#e9ecef');
            return;
        }
        if (input.type === 'file') { input.setAttribute('disabled', 'disabled'); input.value = ''; return; }
        input.setAttribute('readonly', 'readonly');
        if (input.tagName === 'SELECT' || input.type === 'checkbox') input.setAttribute('disabled', 'disabled');
        input.classList.remove('is-valid', 'is-invalid');
        input.style.removeProperty('pointer-events');
        input.style.removeProperty('background-color');
    });

    document.getElementById('formActions').style.display = 'none';
    document.getElementById('viewActions').style.display = 'block';
    ['basic', 'professional', 'family', 'education', 'documents'].forEach(t => clearValidationStates(t));
    const disc = document.getElementById('personalDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('personalSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
    hideSaveError();
}

function toggleSaveBtn(checkboxId, btnId) {
    const checked = document.getElementById(checkboxId).checked;
    const btn = document.getElementById(btnId);
    btn.disabled = !checked;
    btn.style.opacity = checked ? '1' : '0.6';
}

function storeOriginalFormData() {
    originalFormData = {};
    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        if (input.type === 'hidden' || input.type === 'file') return;
        if (!input.name) return;
        originalFormData[input.name] = input.type === 'checkbox' ? input.checked : input.value;
    });
}

function cancelEdit() {
    Object.entries(originalFormData).forEach(([key, value]) => {
        const input = document.querySelector('[name="' + key + '"]');
        if (!input || input.type === 'hidden' || input.type === 'file') return;
        if (input.type === 'checkbox') { input.checked = value; }
        else { input.value = value; }
    });
    localStorage.removeItem('profileDraft');
    localStorage.removeItem('profileEditActive');
    disableEditMode();
    showTabMessage(activeProfileTab, 'Changes cancelled.', 'info');
}

function saveAsDraft() {
    autosaveDraftNow();
    showTabMessage(activeProfileTab, 'Profile saved as draft.', 'info');
}

function showSaveError(html) {
    let box = document.getElementById('saveErrorBox');
    if (!box) {
        box = document.createElement('div');
        box.id = 'saveErrorBox';
        box.className = 'alert alert-danger';
        box.style.cssText = 'margin-bottom:12px;border-left:4px solid #dc3545;';
        const saveBtn = document.getElementById('personalSaveBtn');
        if (saveBtn) saveBtn.parentNode.insertBefore(box, saveBtn);
        else document.getElementById('formActions').appendChild(box);
    }
    box.innerHTML = html;
    box.style.display = 'block';
    setTimeout(() => box.scrollIntoView({ behavior: 'smooth', block: 'center' }), 80);
}

function hideSaveError() {
    const box = document.getElementById('saveErrorBox');
    if (box) box.style.display = 'none';
}

function validateField(event) {
    if (!isEditMode) return true;
    const field = event.target;
    const parentSection = field.closest('.profile-tab-section');
    const isUserEvent = event.type === 'input' || event.type === 'blur' || event.type === 'change';
    if (isUserEvent && parentSection && parentSection.getAttribute('data-tab-group') !== activeProfileTab) return true;
    const validationType = field.getAttribute('data-validation');
    if (!validationType) return true;
    let isValid = true, errorMessage = '';
    field.classList.remove('is-valid', 'is-invalid');
    const existingDynamic = field.parentNode.querySelector('.invalid-feedback.dynamic-error');
    if (existingDynamic) existingDynamic.remove();
    const feedback = field.parentNode.querySelector('.invalid-feedback:not(.dynamic-error)');
    if (feedback) { feedback.textContent = ''; feedback.style.display = 'none'; }
    const val = field.value ? field.value.trim() : '';
    if (!val) { updateTabErrorBadges(); return true; }
    switch (validationType) {
        case 'email': if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val)) { isValid = false; errorMessage = 'Please enter a valid email address.'; } break;
        case 'phone': const pc = val.replace(/\s/g, ''); if (!/^\+?[0-9]+$/.test(pc)) { isValid = false; errorMessage = 'Phone number must contain digits only.'; } else { const d = pc.replace('+', ''); if (d.length < 7 || d.length > 15) { isValid = false; errorMessage = 'Phone must be 7–15 digits.'; } } break;
        case 'digits-only': if (!/^[0-9]+$/.test(val)) { isValid = false; errorMessage = 'Digits only.'; } break;
        case 'alphanumeric': if (!/^[A-Za-z0-9]+$/.test(val)) { isValid = false; errorMessage = 'Letters and digits only.'; } break;
        case 'emirates-id': var eidClean = val.replace(/-/g, ''); if (!/^[0-9]{15}$/.test(eidClean)) { isValid = false; errorMessage = 'Enter your unique 15-digit UAE Emirates ID.'; } break;
        case 'aadhar': if (!/^[0-9]{12}$/.test(val)) { isValid = false; errorMessage = 'Aadhar must be exactly 12 digits.'; } break;
        case 'past-date': const pd = new Date(val); const td1 = new Date(); td1.setHours(0,0,0,0); if (isNaN(pd.getTime())) { isValid = false; errorMessage = 'Enter a valid date.'; } else if (pd > td1) { isValid = false; errorMessage = 'Date cannot be in the future.'; } break;
        case 'future-date': const fd = new Date(val); const td2 = new Date(); td2.setHours(0,0,0,0); if (isNaN(fd.getTime())) { isValid = false; errorMessage = 'Enter a valid date.'; } else if (fd <= td2) { isValid = false; errorMessage = 'Expiry date must be in the future.'; } break;
    }
    if (isValid) { if (isEditMode) field.classList.add('is-valid'); }
    else {
        field.classList.add('is-invalid');
        if (feedback) { feedback.textContent = errorMessage; feedback.style.display = 'block'; }
        else { const errDiv = document.createElement('div'); errDiv.className = 'invalid-feedback dynamic-error'; errDiv.style.cssText = 'display:block;color:#dc3545;font-size:0.8rem;margin-top:3px;'; errDiv.textContent = errorMessage; field.insertAdjacentElement('afterend', errDiv); }
    }
    updateTabErrorBadges();
    return isValid;
}

function updateTabErrorBadges() {
    ['basic', 'professional', 'family', 'education', 'documents'].forEach(tabKey => {
        const tabBtn = document.querySelector('.profile-tab-button[data-tab-target="' + tabKey + '"]');
        if (!tabBtn) return;
        const existing = tabBtn.querySelector('.tab-error-badge');
        if (existing) existing.remove();
        const count = document.querySelectorAll('.profile-tab-section[data-tab-group="' + tabKey + '"] .is-invalid').length;
        if (count > 0) {
            const badge = document.createElement('span');
            badge.className = 'tab-error-badge badge bg-danger ms-1';
            badge.textContent = count;
            tabBtn.appendChild(badge);
        }
    });
}

function clearValidationStates(tabKey) {
    document.querySelectorAll('.profile-tab-section[data-tab-group="' + tabKey + '"]').forEach(section => {
        section.querySelectorAll('input, select').forEach(el => el.classList.remove('is-valid', 'is-invalid'));
        section.querySelectorAll('.invalid-feedback').forEach(el => { el.textContent = ''; el.style.display = 'none'; });
        section.querySelectorAll('.tab-message-box, .dynamic-error').forEach(el => el.remove());
    });
    updateTabErrorBadges();
}

function clearFilePreview(inputEl) {
    const existing = inputEl.parentNode.querySelector('.file-preview-box');
    if (existing) { if (existing._objectURL) URL.revokeObjectURL(existing._objectURL); existing.remove(); }
}

function viewUploadedFile(objectURL, fileType, fileName) {
    if (fileType.startsWith('image/')) {
        const overlay = document.createElement('div');
        overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.75);display:flex;flex-direction:column;align-items:center;justify-content:center;gap:12px;';
        overlay.innerHTML = '<img src="' + objectURL + '" style="max-width:90vw;max-height:85vh;border-radius:8px;"/><button onclick="this.closest(\'div\').remove()" style="background:rgba(255,255,255,0.15);border:1px solid rgba(255,255,255,0.4);color:#fff;border-radius:6px;padding:5px 16px;cursor:pointer;">Close</button>';
        overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
        document.body.appendChild(overlay);
    } else { window.open(objectURL, '_blank'); }
}

function cancelFileUpload(removeBtn) {
    const preview = removeBtn.closest('.file-preview-box');
    if (!preview) return;
    const inputEl = preview.previousElementSibling;
    if (inputEl && inputEl.type === 'file') inputEl.value = '';
    if (preview._objectURL) URL.revokeObjectURL(preview._objectURL);
    preview.remove();
}

function showFilePreview(inputEl, file) {
    clearFilePreview(inputEl);
    const objectURL = URL.createObjectURL(file);
    const preview = document.createElement('div');
    preview.className = 'file-preview-box';
    preview.style.cssText = 'display:flex;align-items:center;gap:10px;margin-top:8px;padding:8px 12px;border:1px solid #198754;border-radius:6px;background:#f0fdf4;font-size:0.85rem;';
    preview.innerHTML = '<span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#155724;"><strong>' + escapeHtml(file.name) + '</strong></span>' +
        '<button type="button" onclick="viewUploadedFile(\'' + objectURL + '\',\'' + escapeHtml(file.type) + '\',\'' + escapeHtml(file.name) + '\')" style="background:none;border:1px solid #0d6efd;color:#0d6efd;border-radius:5px;padding:3px 8px;font-size:0.78rem;cursor:pointer;"><i class="fa fa-eye me-1"></i>View</button>' +
        '<button type="button" class="btn btn-sm btn-outline-danger py-0 px-2" style="font-size:0.78rem;" onclick="cancelFileUpload(this)"><i class="fa fa-times me-1"></i>Remove</button>';
    preview._objectURL = objectURL;
    inputEl.parentNode.insertBefore(preview, inputEl.nextSibling);
}

function showTabMessage(tabKey, text, type) {
    document.querySelectorAll('.tab-message-box').forEach(el => el.remove());
    const firstCard = document.querySelector('.profile-tab-section[data-tab-group="' + tabKey + '"]');
    if (!firstCard) return;
    const alertClass = type === 'success' ? 'alert-success' : type === 'info' ? 'alert-info' : 'alert-danger';
    const icon = type === 'success' ? 'fa-check-circle' : type === 'info' ? 'fa-info-circle' : 'fa-exclamation-triangle';
    const msgDiv = document.createElement('div');
    msgDiv.className = 'tab-message-box alert ' + alertClass + ' alert-dismissible fade show mb-3';
    msgDiv.innerHTML = '<i class="fa ' + icon + ' me-2"></i><span>' + text + '</span><button type="button" class="btn-close" onclick="this.parentNode.remove()"></button>';
    firstCard.parentNode.insertBefore(msgDiv, firstCard);
    msgDiv.scrollIntoView({ behavior: 'smooth', block: 'center' });
    setTimeout(() => { if (msgDiv.parentNode) msgDiv.remove(); }, 5000);
}

document.getElementById('personalDetailsForm').addEventListener('submit', function(e) {
    e.preventDefault();
    if (PENDING_LOCKED) { showSaveError('<i class="fa fa-lock me-2"></i>Editing is locked while your submission is pending HR review.'); return; }
    const disc = document.getElementById('personalDisclaimer');
    if (disc && !disc.checked) { showSaveError('<i class="fa fa-exclamation-triangle me-2"></i>Please read and accept the Employee Disclaimer before saving.'); return; }
    const allTabs = ['basic', 'professional', 'family', 'education', 'documents'];
    const tabNames = {'basic':'Basic Info','professional':'Professional','family':'Family','education':'Education','documents':'Documents'};
    const tabsWithErrors = [];
    allTabs.forEach(tabKey => {
        document.querySelectorAll('.profile-tab-section[data-tab-group="' + tabKey + '"] input[data-validation], .profile-tab-section[data-tab-group="' + tabKey + '"] select[data-validation]').forEach(input => {
            if (!validateField({ target: input, type: 'submit' })) { if (!tabsWithErrors.includes(tabKey)) tabsWithErrors.push(tabKey); }
        });
    });
    updateTabErrorBadges();
    if (tabsWithErrors.length > 0) {
        showSaveError('<i class="fa fa-exclamation-triangle me-2"></i>Please fix errors in: ' + tabsWithErrors.map(t => '<strong>' + (tabNames[t]||t) + '</strong>').join(', '));
        return;
    }
    hideSaveError();
    const toReenable = [];
    document.querySelectorAll('#personalDetailsForm select[disabled], #personalDetailsForm input[type="checkbox"][disabled]').forEach(el => {
        if (!el.hasAttribute('data-always-readonly') && el.type !== 'file') { el.removeAttribute('disabled'); toReenable.push(el); }
    });
    const formData = new FormData(this);
    const csrfToken = document.querySelector('input[name="csrf_token"]').value;
    toReenable.forEach(el => el.setAttribute('disabled', 'disabled'));
    fetch('/my/employee/personal', { method: 'POST', body: formData, headers: { 'X-CSRFToken': csrfToken } })
    .then(r => r.json())
    .then(data => {
        if (data.success) {
            disableEditMode();
            localStorage.removeItem('profileDraft');
            localStorage.removeItem('profileEditActive');
            if (data.no_change) {
                showTabMessage(activeProfileTab, 'No changes detected. Profile is already up to date.', 'info');
            } else {
                const ref = data.reference || '';
                showTabMessage(activeProfileTab, 'Changes submitted to HR for review.' + (ref ? ' Reference: <strong>' + ref + '</strong>' : ''), 'success');
            }
        } else {
            showTabMessage(activeProfileTab, 'Error: ' + (data.error || 'Unknown error'), 'error');
        }
    })
    .catch(err => { showTabMessage(activeProfileTab, 'Network error. Please try again.', 'error'); });
});

document.addEventListener('DOMContentLoaded', function() {
    document.querySelectorAll('#personalDetailsForm .profile-tab-button').forEach(button => {
        button.addEventListener('click', function() { switchProfileTab(this.getAttribute('data-tab-target')); });
    });
    switchProfileTab(activeProfileTab);
    document.querySelectorAll('.edit-mode-toggle').forEach(t => t.checked = false);
    document.getElementById('formActions').style.display = 'none';
    document.getElementById('viewActions').style.display = 'block';
    isEditMode = false;
    document.querySelectorAll('#personalDetailsForm input[type="file"].file-upload-input').forEach(fi => fi.setAttribute('disabled', 'disabled'));

    const draftRaw = localStorage.getItem('profileDraft');
    const wasEditing = localStorage.getItem('profileEditActive') === '1';
    localStorage.removeItem('profileEditActive');

    window.addEventListener('beforeunload', function() {
        if (isEditMode) {
            const draftData = {};
            document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(function(input) {
                if (input.type === 'hidden' || input.type === 'file') return;
                if (!input.name) return;
                draftData[input.name] = input.type === 'checkbox' ? (input.checked ? 'on' : '') : input.value;
            });
            try { localStorage.setItem('profileDraft', JSON.stringify(draftData)); localStorage.setItem('profileEditActive', '1'); } catch(e) {}
        }
    });

    if (draftRaw && wasEditing && !PENDING_LOCKED) {
        try {
            const draft = JSON.parse(draftRaw);
            enableEditMode();
            Object.entries(draft).forEach(function([key, value]) {
                const input = document.querySelector('[name="' + key + '"]');
                if (!input || input.type === 'hidden' || input.type === 'file') return;
                input.type === 'checkbox' ? (input.checked = value === 'on') : (input.value = value);
            });
            showTabMessage(activeProfileTab, 'Your unsaved changes have been restored.', 'info');
        } catch (ex) { localStorage.removeItem('profileDraft'); }
    }

    if (PENDING_LOCKED) {
        document.querySelectorAll('.edit-mode-toggle').forEach(t => {
            t.closest('.form-check.form-switch') && (t.closest('.form-check.form-switch').style.display = 'none');
        });
        var editBtn = document.getElementById('editProfileBtn');
        if (editBtn) { editBtn.disabled = true; editBtn.title = 'Editing locked — pending HR review'; }
    }

    /* ══════════════════════════════════════════════════════════════════════
       PAGE LOAD: Populate all three state dropdowns using _fetchStates.
       Timeout 300ms ensures country select values are fully rendered.
       data-saved-value holds the server-rendered state ID for pre-selection.
    ══════════════════════════════════════════════════════════════════════ */
    setTimeout(function() {
        /* 1. Work Location: countries_id → statesDropdown */
        var workCountrySel = document.querySelector('select[name="countries_id"]');
        var workStateSel   = document.getElementById('statesDropdown');
        if (workCountrySel && workCountrySel.value && workStateSel) {
            var savedWork = workStateSel.getAttribute('data-saved-value') || '0';
            _fetchStates(workStateSel, workCountrySel.value, savedWork);
        }

        /* 2. Permanent Address: private_country_id → permanentStateDropdown */
        var permCountrySel = document.querySelector('select[name="private_country_id"]');
        var permStateSel   = document.getElementById('permanentStateDropdown');
        if (permCountrySel && permCountrySel.value && permStateSel) {
            var savedPerm = permStateSel.getAttribute('data-saved-value') || '0';
            _fetchStates(permStateSel, permCountrySel.value, savedPerm);
        }

        /* 3. Contact Information: country_residences_id → contactStateDropdown */
        var contactCountrySel = document.querySelector('select[name="country_residences_id"]');
        var contactStateSel   = document.getElementById('contactStateDropdown');
        if (contactCountrySel && contactCountrySel.value && contactStateSel) {
            var savedContact = contactStateSel.getAttribute('data-saved-value') || '0';
            _fetchStates(contactStateSel, contactCountrySel.value, savedContact);
        }
    }, 300);
});
